// Shift_JIS-encoded 内閣府 syukujitsu.csv fixtures (base64), derived from a
// real subset of the official file (fetched 2026-07-10, 1955/1956/2024-2027
// rows kept) so dates/names are realistic rather than invented. Stored as
// base64 text (not raw binary files) so the byte sequence survives Vite's
// module transform untouched — see docs/architecture/data-ingestion-pattern.md.
//
// Scenarios:
//   validBase         — 93 rows, the "current production state" baseline.
//   validUpdated       — validBase with one row removed (2027/11/23), one
//                        row renamed (2026/2/11), and one row added
//                        (2028/1/1) — exercises diff() add/remove/change.
//   truncated          — first 46 rows of validBase only (>5% decrease from a
//                        93-row baseline) — must fail validate().
//   invalidDateFormat  — validBase with one date replaced by "1955/13/99"
//                        (invalid month/day) — must fail validate().
//   yearOutOfRange     — validBase with one date replaced by "1900/4/29"
//                        (below the 1955 floor) — must fail validate().
export const FIXTURES_BASE64 = {
  validBase:
    "",
  validUpdated:
    "",
  truncated:
    "",
  invalidDateFormat:
    "",
  yearOutOfRange:
    "",
} as const;

export type FixtureKey = keyof typeof FIXTURES_BASE64;

/** Decode a base64 fixture to the exact Shift_JIS byte sequence it represents. */
export function fixtureBytes(key: FixtureKey): Uint8Array {
  const binary = atob(FIXTURES_BASE64[key]);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}
